  WEB3_CHAT_MODE: process.env.WEB3_CHAT_MODE || "on",
  AI_TIMEOUT_MS: num(process.env.AI_TIMEOUT_MS || "600000", 600000),
  AI_MAX_RETRIES: num(process.env.AI_MAX_RETRIES || "2", 2),
  CONCURRENCY: num(process.env.CONCURRENCY || "20", 20),

